('costo-inaccion', 'I. Contabilidad Ambiental: Costo de Inacción', 'I. Contabilidad Ambiental: Cost of Inaction', 'Te muestra cuánto dinero perderá tu negocio si no empiezas a ser sostenible hoy mismo antes de que lleguen las multas.', 'Shows money lost if you don't become sustainable before fines arrive.', 'AlertTriangle', '[{"name": "input", "type": "textarea", "label_es": "Describe tu necesidad", "label_en": "Describe your need", "required": true}]'::jsonb, '[]'::jsonb, 'GENERAL INSTRUCTIONS: You are an expert Environmental Consultant. Respond in {{responseLanguage}}. Task: Process {{input}} for Cost of Inaction'),
('auditor-activos', 'I. Contabilidad Ambiental: Auditor de Activos Verificables', 'I. Contabilidad Ambiental: Verifiable Assets Auditor', 'Revisa que tus datos sean tan sólidos que cualquier auditor internacional pueda darles el visto bueno.', 'Checks data solidity for international auditors' approval.', 'CheckShield', '[{"name": "input", "type": "textarea", "label_es": "Describe tu necesidad", "label_en": "Describe your need", "required": true}]'::jsonb, '[]'::jsonb, 'GENERAL INSTRUCTIONS: You are an expert Environmental Consultant. Respond in {{responseLanguage}}. Task: Process {{input}} for Verifiable Assets Auditor'),
('simulador-externalidades', 'I. Contabilidad Ambiental: Simulador de Externalidades', 'I. Contabilidad Ambiental: Externalities Simulator', 'Calcula cuánto le cuesta al planeta tu operación y cómo eso afecta tu rentabilidad real.', 'Calculates planet cost of your operation and real profitability impact.', 'Globe', '[{"name": "input", "type": "textarea", "label_es": "Describe tu necesidad", "label_en": "Describe your need", "required": true}]'::jsonb, '[]'::jsonb, 'GENERAL INSTRUCTIONS: You are an expert Environmental Consultant. Respond in {{responseLanguage}}. Task: Process {{input}} for Externalities Simulator'),
