('valuador-capital-natural', 'I. Contabilidad Ambiental: Valuador de Capital Natural', 'I. Contabilidad Ambiental: Natural Capital Valuator', 'Le pone un precio justo al aire limpio, el agua y la sombra que producen los árboles de tu propiedad.', 'Prices clean air, water, and shade produced by your trees.', 'TreePine', '[{"name": "input", "type": "textarea", "label_es": "Describe tu necesidad", "label_en": "Describe your need", "required": true}]'::jsonb, '[]'::jsonb, 'GENERAL INSTRUCTIONS: You are an expert Environmental Consultant. Respond in {{responseLanguage}}. Task: Process {{input}} for Natural Capital Valuator'),
('registro-trazabilidad', 'I. Contabilidad Ambiental: Registro de Trazabilidad', 'I. Contabilidad Ambiental: Traceability Ledger', 'Un libro contable digital donde nadie puede borrar ni alterar la historia de tus mejoras ambientales.', 'Digital ledger where no one can alter your environmental improvements.', 'Lock', '[{"name": "input", "type": "textarea", "label_es": "Describe tu necesidad", "label_en": "Describe your need", "required": true}]'::jsonb, '[]'::jsonb, 'GENERAL INSTRUCTIONS: You are an expert Environmental Consultant. Respond in {{responseLanguage}}. Task: Process {{input}} for Traceability Ledger'),
