-- Script de inserción de 120 Micro-Apps para Vertical Medio Ambiente

DELETE FROM app_executions;
DELETE FROM plan_apps;
DELETE FROM user_app_overrides;
DELETE FROM micro_apps;

ON CONFLICT (slug) DO UPDATE SET
  name_es = EXCLUDED.name_es,
  name_en = EXCLUDED.name_en,
  description_es = EXCLUDED.description_es,
  description_en = EXCLUDED.description_en,
  icon = EXCLUDED.icon,
  form_schema = EXCLUDED.form_schema,
  prompt_template = EXCLUDED.prompt_template;


-- Vinculación de Apps a Planes

-- 1. Primero, asegurarse de que los planes existan según la nueva estructura
DELETE FROM plans;


ON CONFLICT (slug) DO UPDATE SET 
  name_es = EXCLUDED.name_es, 
  name_en = EXCLUDED.name_en, 
  price_monthly = EXCLUDED.price_monthly,
  app_limit = EXCLUDED.app_limit,
  description_es = EXCLUDED.description_es,
  description_en = EXCLUDED.description_en,
  sort_order = EXCLUDED.sort_order;

-- 2. Vincular Apps Demo del Segmento Maestro al Plan Gratuito (slug: gratis)
SELECT p.id, m.id FROM plans p, micro_apps m 
WHERE p.slug = 'gratis' AND m.slug IN ('hogar-sano', 'corp-eco-manager', 'comunidad-circular', 'eco-campus', 'gov-impact-mon')
ON CONFLICT DO NOTHING;

-- 3. Vincular Todas las Apps a los demás planes (el desbloqueo lo limita app_limit en el backend)
SELECT p.id, m.id FROM plans p, micro_apps m 
WHERE p.slug IN ('crecimiento-10', 'crecimiento-30', 'crecimiento-max', 'elite', 'master')
ON CONFLICT DO NOTHING;
